import json, urllib.request

def req(method, url, body=None):
    r = urllib.request.Request('http://localhost:9274'+url, method=method,
        data=json.dumps(body).encode() if body else None,
        headers={'Content-Type':'application/json'})
    try:
        return json.load(urllib.request.urlopen(r))
    except Exception as e:
        return {'error': str(e)}

maps = req('GET','/ax-*/_mapping')
for idx in sorted(maps):
    props = maps[idx].get('mappings',{}).get('properties',{})
    should = []
    for f,p in props.items():
        t = p.get('type')
        if t == 'keyword':
            should.append({'wildcard':{f:{'value':'*u-1042*'}}})
        elif t in ('text','semantic_text'):
            should.append({'match_phrase':{f:'u-1042'}})
    if not should: continue
    res = req('POST', f'/{idx}/_search', {'size':0,'query':{'bool':{'should':should,'minimum_should_match':1}}})
    if 'error' in res or res.get('hits') is None:
        print(idx, 'ERROR', str(res)[:200]); continue
    total = res['hits']['total']['value']
    if total:
        # which fields matched
        fields = []
        for c in should:
            r2 = req('POST', f'/{idx}/_search', {'size':0,'query':c})
            n = r2.get('hits',{}).get('total',{}).get('value',0) if 'error' not in r2 else 0
            if n: fields.append(f"{list(c[list(c)[0]].keys())[0]}={n}")
        print(f"{idx}: {total} hits  [{', '.join(fields)}]")
