import json, urllib.request
def req(url, body):
    r = urllib.request.Request('http://localhost:9274'+url, method='POST',
        data=json.dumps(body).encode(), headers={'Content-Type':'application/json'})
    try: return json.load(urllib.request.urlopen(r))
    except Exception as e: return {'error':str(e)}

# indirect references in text-bearing indices
for idx, fields in [('ax-notes',['body','title']),('ax-docs',['body','title']),
                    ('ax-docs-docx',['body','title']),('ax-docs-html',['body','headings','title']),
                    ('ax-api-fixtures',['payload_hits'])]:
    for f in fields:
        for phrase in ['cai.reyes1042@globex.example','cai.reyes1042','User 1042']:
            res = req(f'/{idx}/_search', {'size':0,'query':{'match_phrase':{f:phrase}}})
            n = res.get('hits',{}).get('total',{}).get('value',0)
            if n: print(f"{idx}.{f} phrase '{phrase}': {n}")

# map hit indices to source paths via ax_path terms agg
for idx in ['ax-db-audit-log','ax-db-chat-usage','ax-db-orders','ax-db-users','ax-docs-html',
            'ax-events','ax-events-archive','ax-exports-csv-orders-march','ax-exports-csv-users',
            'ax-logs-app','ax-logs-nginx']:
    fld = 'user' if idx.startswith('ax-logs') else 'user_id'
    q = {'match_phrase':{'body':'u-1042'}} if idx=='ax-docs-html' else {'term':{fld:'u-1042'}}
    res = req(f'/{idx}/_search', {'size':0,'query':q,'aggs':{'p':{'terms':{'field':'ax_path','size':5}}},'track_total_hits':True})
    b = res.get('aggregations',{}).get('p',{}).get('buckets',[])
    tot = res.get('hits',{}).get('total',{}).get('value')
    paths = ', '.join(x['key'] for x in b[:3]) or '(agg empty)'
    # fallback: sample a doc
    if not b:
        res2 = req(f'/{idx}/_search', {'size':1,'query':q,'_source':['ax_path','ax_format']})
        h = res2.get('hits',{}).get('hits',[])
        if h: paths = h[0]['_source'].get('ax_path','?') + ' (sample)'
    print(f"{idx}: {tot} hits — {paths}")
EOF
